function getLocalOpps(){try{return JSON.parse(localStorage.getItem("oct_localopps")||"[]")}catch(e){return[]}}
function saveLocalOpps(a){localStorage.setItem("oct_localopps",JSON.stringify(a))}
function daysUntil(d){if(!d)return null;return Math.ceil((new Date(d)-today)/864e5)}
function deadlineLabel(d){if(!d)return{text:"全年开放",cls:"deadline-rolling"};var n=new Date(d),a=daysUntil(d);return a<0?{text:"已截止",cls:"deadline-expired"}:a<=7?{text:"即将截止！("+n.toLocaleDateString("zh-CN")+")",cls:"deadline-soon"}:{text:"截止: "+n.toLocaleDateString("zh-CN"),cls:""}}
function deadlineSortVal(d){return d?new Date(d).getTime():9999999999999}
function timeAgo(d){var n=Math.floor((today-new Date(d))/864e5);return n===0?"今天":n===1?"昨天":n<7?n+"天前":n<30?Math.floor(n/7)+"周前":new Date(d).toLocaleDateString("zh-CN")}
