let currentSearch="";
let currentSort="newest";
function render(){let items=opportunities.concat(supabaseOpps).concat(getLocalOpps().map(function(o){o._local=true;return o}));if(currentView==="local")items=getLocalOpps().map(function(o){o._local=true;return o});else if(currentView!=="all")items=items.filter(function(o){return o.type===currentView});if(currentSearch){var q=currentSearch.toLowerCase();items=items.filter(function(o){return o.title.toLowerCase().indexOf(q)!==-1||o.organization.toLowerCase().indexOf(q)!==-1||o.location.toLowerCase().indexOf(q)!==-1||(o.description||"").toLowerCase().indexOf(q)!==-1})}if(currentSort==="deadline")items.sort(function(a,b){return deadlineSortVal(a.deadline)-deadlineSortVal(b.deadline)});else if(currentSort==="deadline-desc")items.sort(function(a,b){return deadlineSortVal(b.deadline)-deadlineSortVal(a.deadline)});else items.sort(function(a,b){return new Date(b.posted_at)-new Date(a.posted_at)});document.getElementById("resultCount").textContent="共 "+items.length+" 个机会";var grid=document.getElementById("cardsGrid");if(items.length===0){grid.innerHTML='<div class="empty-state"><svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg><p>没有找到匹配的机会</p></div>';return}grid.innerHTML=items.map(function(o){var l=deadlineLabel(o.deadline);var bc=TYPE_CLASS[o.type],bl=TYPE_LABELS[o.type];if(o._local){bc="local";bl="社区提交"}return'<div class="card" data-id="'+o.id+'"><div class="card-body"><span class="card-badge '+bc+'">'+bl+'</span><h2 class="card-title">'+o.title+'</h2><div class="card-org">'+o.organization+'</div><div class="card-meta"><span><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg><span class="'+l.cls+'">'+l.text+'</span></span><span><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg>'+o.location+'</span></div><div class="card-tags">'+(o.disciplines||[]).map(function(d){return'<span class="card-tag">'+d+'</span>'}).join("")+'</div><p class="card-desc">'+o.description+'</p></div><div class="card-footer"><button class="card-btn view-details" data-id="'+o.id+'">查看详情</button></div></div>'}).join("");document.querySelectorAll(".view-details").forEach(function(btn){btn.addEventListener("click",function(e){e.stopPropagation();var id=btn.getAttribute("data-id");openModal(id)})});document.querySelectorAll(".card").forEach(function(card){card.addEventListener("click",function(){var id=card.getAttribute("data-id");openModal(id)})})}
function openModal(id){var all=opportunities.concat(getLocalOpps().map(function(o){o._local=true;return o}));var o=all.find(function(x){return x.id===id});if(!o)return;var l=deadlineLabel(o.deadline);var bc=TYPE_CLASS[o.type],bl=TYPE_LABELS[o.type];if(o._local){bc="local";bl="社区提交"}document.getElementById("modalContent").innerHTML='<span class="card-badge '+bc+'">'+bl+'</span><h2 class="modal-title">'+o.title+'</h2><div class="modal-org">'+o.organization+'</div><div class="modal-meta"><div class="modal-meta-item"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg><strong>截止日期：</strong><span class="'+l.cls+'">'+l.text+'</span></div><div class="modal-meta-item"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"/><circle cx="12" cy="10" r="3"/></svg><strong>地点：</strong>'+o.location+'</div><div class="modal-meta-item"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"/><path d="M19 10v2a7 7 0 0 1-14 0v-2"/><line x1="12" y1="19" x2="12" y2="23"/><line x1="8" y1="23" x2="16" y2="23"/></svg><strong>资金：</strong>'+(o.funding||"未说明")+'</div></div><div class="modal-section"><h3>描述</h3><p>'+o.description+'</p></div><div class="modal-section"><h3>适用学科</h3><div class="modal-tags">'+(o.disciplines||[]).map(function(d){return'<span class="modal-tag">'+d+'</span>'}).join("")+'</div></div><a href="'+o.url+'" target="_blank" rel="noopener" class="modal-link"><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/><polyline points="15 3 21 3 21 9"/><line x1="10" y1="14" x2="21" y2="3"/></svg>查看原文 / 申请</a>';document.getElementById("modalOverlay").classList.add("open");document.body.style.overflow="hidden"}
function closeModal(){document.getElementById("modalOverlay").classList.remove("open");document.body.style.overflow=""}
document.addEventListener("DOMContentLoaded",async function(){await loadFromSupabase();render();document.querySelectorAll(".nav-btn").forEach(function(btn){btn.addEventListener("click",function(){document.querySelectorAll(".nav-btn").forEach(function(b){b.classList.remove("active")});btn.classList.add("active");currentView=btn.getAttribute("data-view");render()})});document.getElementById("searchInput").addEventListener("input",function(){currentSearch=this.value;render()});document.getElementById("sortSelect").addEventListener("change",function(){currentSort=this.value;render()});document.getElementById("submitBtn").addEventListener("click",function(){document.getElementById("submitOverlay").classList.add("open");document.body.style.overflow="hidden";document.getElementById("submitSuccess").style.display="none";document.getElementById("submitForm").style.display="flex"});document.getElementById("submitClose").addEventListener("click",function(){document.getElementById("submitOverlay").classList.remove("open");document.body.style.overflow=""});document.getElementById("submitOverlay").addEventListener("click",function(e){if(e.target===this){document.getElementById("submitOverlay").classList.remove("open");document.body.style.overflow=""}});document.getElementById("submitForm").addEventListener("submit",function(e){e.preventDefault();var f=e.target;var id="local_"+Date.now();var item={id:id,type:f.formType.value,title:f.formTitle.value,organization:f.formOrg.value,deadline:f.formDeadline.value||null,location:f.formLocation.value,disciplines:f.formDisciplines.value?f.formDisciplines.value.split(",").map(function(s){return s.trim()}):[],funding:f.formFunding.value||"",description:f.formDesc.value,url:f.formUrl.value,source:"社区提交",posted_at:new Date().toISOString().slice(0,10),featured:false};var opps=getLocalOpps();opps.unshift(item);saveLocalOpps(opps);if(!SB_URL.startsWith("https://YOUR_PROJECT")){try{var sb=window.supabase.createClient(SB_URL,SB_KEY);sb.from("opportunities").insert({title:item.title,type:item.type,organization:item.organization,deadline:item.deadline||null,location:item.location,disciplines:item.disciplines,funding:item.funding||null,description:item.description,url:item.url||null,source:"community",posted_at:item.posted_at,featured:false,is_local:true,status:"draft"}).execute()}catch(e){}}document.getElementById("submitForm").style.display="none";document.getElementById("submitSuccess").style.display="flex";f.reset();if(currentView!=="local"){currentView="local";document.querySelectorAll(".nav-btn").forEach(function(b){b.classList.remove("active")});document.querySelector('.nav-btn[data-view="local"]').classList.add("active")}render()});document.getElementById("submitAnother").addEventListener("click",function(){document.getElementById("submitSuccess").style.display="none";document.getElementById("submitForm").style.display="flex"});document.getElementById("modalClose").addEventListener("click",closeModal);document.getElementById("modalOverlay").addEventListener("click",function(e){if(e.target===this)closeModal()});document.addEventListener("keydown",function(e){if(e.key==="Escape")closeModal()})});

